#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;int head[N],des[N<<1],nxt[N<<1],cgt;
inline void ins(int x,int y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;
}
int n,x[N],y[N],lx[N],ly[N];bool col[N],vis[N];
inline void dfs(int u,bool c=0)
{
	if(vis[u])return; col[u]=c; vis[u]=true;
	for(int i(head[u]);i;i=nxt[i])dfs(des[i],c^1);
}
int main()
{
	n=read();rep(1,n,i)
	{
		int x=read(),y=read();
		if(lx[x]){ins(i,lx[x]);lx[x]=0;}else lx[x]=i;
		if(ly[y]){ins(i,ly[y]);ly[y]=0;}else ly[y]=i;
	}
	rep(1,n,i)dfs(i);
	rep(1,n,i)putchar(col[i]?'r':'b');puts("");
}
